# Test fixture for ast_pure_functions macro
# Functions are ordered by expected purity result for easy test authoring

# --- Pure functions ---
# Arithmetic and comparisons on parameters only; no function calls, no attribute access

def add(x, y):
    return x + y

def multiply(x, y):
    return x * y

def negate(x):
    return -x

def clamp(value, low, high):
    if value < low:
        return low
    elif value > high:
        return high
    return value

def concat(a, b):
    return a + b

# --- Impure: calls non-local function ---

def print_value(x):
    print(x)
    return x

def use_len(items):
    return len(items)

# --- Impure: attribute access on non-parameter object ---

def use_os():
    import os
    return os.getcwd()

# --- Impure: explicit global statement ---

_counter = 0

def increment():
    global _counter
    _counter += 1
    return _counter

# --- Impure: attribute access where object is a local variable, not a param ---

def read_file(path):
    f = open(path)
    return f.read()

# --- Edge case: method call on parameter is pure (object IS a param) ---
# x.upper() should NOT be flagged because x is a parameter

def shout(x):
    return x.upper()
